export function sortIntegers(arr: readonly number[]): number[] {
  return [...arr].sort((a, b) => a - b);
}

export function binarySearch(arr: readonly number[], target: number): number {
  let lo = 0;
  let hi = arr.length - 1;
  while (lo <= hi) {
    const mid = (lo + hi) >>> 1;
    if (arr[mid] === target) return mid;
    if ((arr[mid] as number) < target) lo = mid + 1;
    else hi = mid - 1;
  }
  return -1;
}

export function clamp(value: number, min: number, max: number): number {
  return Math.max(min, Math.min(max, value));
}

export function parseIntSafe(s: string): number | null {
  const trimmed = s.trim();
  if (!/^-?\d+$/.test(trimmed)) return null;
  const n = Number(trimmed);
  if (!Number.isSafeInteger(n)) return null;
  return n;
}

export function isSafeInt(n: number): boolean {
  return Number.isSafeInteger(n);
}

export function decToHex(n: number): string {
  return n.toString(16);
}

export function padLeft(s: string, length: number, char: string): string {
  return s.padStart(length, char);
}

export function countOccurrences(items: readonly string[]): Map<string, number> {
  const counts = new Map<string, number>();
  for (const item of items) {
    counts.set(item, (counts.get(item) ?? 0) + 1);
  }
  return counts;
}

export function mostFrequent(items: readonly string[]): string | null {
  if (items.length === 0) return null;
  const counts = countOccurrences(items);
  let best: string | null = null;
  let bestCount = 0;
  for (const [item, count] of counts) {
    if (count > bestCount) {
      best = item;
      bestCount = count;
    }
  }
  return best;
}

export function arraysEqualAsMultisets(a: readonly string[], b: readonly string[]): boolean {
  if (a.length !== b.length) return false;
  const countA = countOccurrences(a);
  const countB = countOccurrences(b);
  for (const [key, val] of countA) {
    if (countB.get(key) !== val) return false;
  }
  return true;
}

export function splitAndTrim(s: string, delimiter: string): string[] {
  return s.split(delimiter).map(t => t.trim()).filter(t => t.length > 0);
}

export function isValidIdentifier(s: string): boolean {
  return /^[a-zA-Z_][a-zA-Z0-9_]*$/.test(s);
}

export function camelToSnake(s: string): string {
  return s.replace(/([A-Z])/g, '_$1').toLowerCase().replace(/^_/, '');
}

export function truncate(s: string, maxLen: number): string {
  if (s.length <= maxLen) return s;
  return s.slice(0, maxLen - 1) + '\u2026';
}
